import React from 'react';
import { UserCheck, ArrowRight } from 'lucide-react';

const StaffPermissions = () => {
  return (
    <div className="space-y-6">
      <h2 className="text-2xl font-bold text-gray-900">Staff Permissions</h2>
      <div className="p-12 bg-gradient-to-br from-indigo-50 to-blue-50 border-2 border-dashed border-indigo-300 rounded-xl text-center">
        <UserCheck className="w-16 h-16 text-indigo-400 mx-auto mb-4" />
        <h3 className="text-xl font-semibold text-gray-900 mb-2">Coming Soon</h3>
        <p className="text-gray-600 mb-6">Staff permission management is being developed</p>
        <a href="/admin/users" className="inline-flex items-center gap-2 px-4 py-2 bg-indigo-500 text-white rounded-lg hover:bg-indigo-600 transition-colors">
          <ArrowRight className="w-4 h-4" />
          Manage Users
        </a>
      </div>
    </div>
  );
};

export default StaffPermissions;
